export interface Reservoir {
  id: string;
  name: string;
  location: [number, number]; // Lat, Lng
  maxCapacity: number; // MCM (Million Cubic Meters)
  fullLevel: number; // Meters
  description: string;
}

export interface SeasonalData {
  season: 'Winter' | 'Summer' | 'Monsoon' | 'Post-Monsoon';
  year: number;
  waterLevel: number; // Meters
  surfaceArea: number; // Sq Km
  volume: number; // MCM
  rainfall: number; // mm
  cloudCover: number; // %
}

export interface SimulationState {
  selectedReservoirId: string;
  year: number;
  season: SeasonalData['season'];
}

export interface AIAnalysisResult {
  riskLevel: 'Low' | 'Moderate' | 'High' | 'Critical';
  summary: string;
  recommendation: string;
}

import { Reservoir, SeasonalData } from '../types';

export const RESERVOIRS: Reservoir[] = [
  {
    id: 'res-1',
    name: 'Emerald Lake Reservoir',
    location: [12.9716, 77.5946], // Near Bangalore
    maxCapacity: 500,
    fullLevel: 120,
    description: 'A major source of irrigation for the southern district.'
  },
  {
    id: 'res-2',
    name: 'Sapphire Dam',
    location: [19.0760, 72.8777], // Near Mumbai
    maxCapacity: 1200,
    fullLevel: 250,
    description: 'Critical drinking water supply with high seasonal variance.'
  },
  {
    id: 'res-3',
