    maxCapacity: 300,
    fullLevel: 80,
    description: 'Urban catchment area prone to rapid evaporation.'
  }
];

// Helper to generate a rough polygon (circle-ish) for the map based on volume
export const generateWaterPolygon = (center: [number, number], volumePct: number) => {
  const points = [];
  const sides = 20;
  const baseRadius = 0.02 * (volumePct / 100); // Degrees approx

  for (let i = 0; i < sides; i++) {
    const angle = (i * 360) / sides;
    const rad = (angle * Math.PI) / 180;
    // Add some noise to make it look organic
    const r = baseRadius * (0.8 + Math.random() * 0.4); 
    const lat = center[0] + r * Math.cos(rad);
    const lng = center[1] + r * Math.sin(rad) * 1.2; // Slight oval
    points.push([lat, lng]);
  }
  return points;
};

// Generate historical data
export const getHistoricalData = (reservoirId: string): SeasonalData[] => {
  const data: SeasonalData[] = [];
  const startYear = 2020;
  const seasons: SeasonalData['season'][] = ['Winter', 'Summer', 'Monsoon', 'Post-Monsoon'];

  // Deterministic "random" based on ID
  const seed = reservoirId.charCodeAt(reservoirId.length - 1);

  for (let year = startYear; year <= 2024; year++) {
    seasons.forEach((season, index) => {
      let baseVol = 50; // %
      if (season === 'Monsoon') baseVol = 90;
      if (season === 'Post-Monsoon') baseVol = 80;
      if (season === 'Winter') baseVol = 60;
      if (season === 'Summer') baseVol = 30;

      // Trend: slowly drying up or varying
      const trend = (year - startYear) * (seed % 2 === 0 ? -2 : 1); 
      const noise = (Math.sin(year * index) * 10);

      const volume = Math.max(10, Math.min(100, baseVol + trend + noise));

      // Derived metrics
      const maxVol = RESERVOIRS.find(r => r.id === reservoirId)?.maxCapacity || 500;
      const actualVolume = Math.round((volume / 100) * maxVol);
      const surfaceArea = Math.round(actualVolume * 0.15 * 100) / 100; // Rough correlation
      const waterLevel = Math.round((volume / 100) * 100 * 10) / 10;
      const rainfall = season === 'Monsoon' ? 800 + noise * 10 : 50 + noise;

      data.push({
        season,
        year,
        volume: actualVolume,
        waterLevel,
        surfaceArea,
        rainfall: Math.max(0, Math.round(rainfall)),
        cloudCover: season === 'Monsoon' ? 80 : 10
      });
    });
  }
  return data;
};

import { GoogleGenAI, SchemaType } from "@google/genai";
import { SeasonalData, Reservoir, AIAnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateHydrologicalReport = async (
  reservoir: Reservoir,
  currentData: SeasonalData,
  historicalTrend: SeasonalData[]
): Promise<AIAnalysisResult> => {

  const prompt = `
    Analyze the following hydrological data for a reservoir and provide a risk assessment and summary.

    Reservoir: ${reservoir.name} (${reservoir.description})
    Current Status (${currentData.season} ${currentData.year}):
    - Volume: ${currentData.volume} MCM (Max: ${reservoir.maxCapacity} MCM)
    - Water Level: ${currentData.waterLevel} meters
    - Surface Area: ${currentData.surfaceArea} sq km
    - Rainfall: ${currentData.rainfall} mm

    Historical Context:
    The average volume over the last few seasons was roughly ${
      historicalTrend.reduce((acc, curr) => acc + curr.volume, 0) / historicalTrend.length
    } MCM.

    Provide a JSON response with:
    1. riskLevel: 'Low', 'Moderate', 'High', or 'Critical' (based on drought/flood risk).
    2. summary: A 2-sentence executive summary of the water situation.
    3. recommendation: A specific operational recommendation (e.g., release water, conserve, desilt).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: SchemaType.OBJECT,
          properties: {
            riskLevel: { type: SchemaType.STRING, enum: ['Low', 'Moderate', 'High', 'Critical'] },
            summary: { type: SchemaType.STRING },
            recommendation: { type: SchemaType.STRING }
          },
          required: ['riskLevel', 'summary', 'recommendation']
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AIAnalysisResult;
    }
    throw new Error("Empty response from AI");
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      riskLevel: 'Moderate',
      summary: 'AI analysis unavailable. Standard monitoring protocols apply.',
      recommendation: 'Continue manual observation.'
    };
  }
};

import React, { useEffect, useMemo } from 'react';
import { MapContainer, TileLayer, Polygon, CircleMarker, Popup, useMap } from 'react-leaflet';
import { Reservoir, SeasonalData } from '../types';
import { generateWaterPolygon } from '../services/mockData';
import L from 'leaflet';

// Fix for default Leaflet icons in React
// @ts-ignore
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png',
});

interface MapVisualizerProps {
  reservoir: Reservoir;
  data: SeasonalData;
}

const MapUpdater: React.FC<{ center: [number, number] }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo(center, 13);
  }, [center, map]);
  return null;
};

const MapVisualizer: React.FC<MapVisualizerProps> = ({ reservoir, data }) => {

  const waterPolygon = useMemo(() => {
    const volPct = (data.volume / reservoir.maxCapacity) * 100;
    return generateWaterPolygon(reservoir.location, volPct);
  }, [reservoir, data]);

  const mapOptions = {
      fillColor: '#3b82f6',
      fillOpacity: 0.6,
      color: '#2563eb',
      weight: 2
  };

  return (
    <div className="h-full w-full rounded-xl overflow-hidden border border-slate-700 shadow-2xl relative">
      <MapContainer 
        center={reservoir.location} 
        zoom={13} 
        style={{ height: '100%', width: '100%', background: '#0f172a' }}
        scrollWheelZoom={false}
      >
        {/* Dark Matter-like tiles for that sci-fi/dashboard look */}
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
        />

        <MapUpdater center={reservoir.location} />

        <Polygon positions={waterPolygon as any} pathOptions={mapOptions}>
           <Popup>
            <div className="text-slate-900">
              <strong>{reservoir.name}</strong><br/>
              Water Spread: {data.surfaceArea} km²<br/>
              Volume: {data.volume} MCM
            </div>
          </Popup>
        </Polygon>

        <CircleMarker center={reservoir.location} radius={2} pathOptions={{color: 'white', opacity: 0.5}} />

      </MapContainer>

      {/* Overlay Info */}
      <div className="absolute top-4 right-4 z-[400] bg-slate-900/80 backdrop-blur-md p-3 rounded-lg border border-slate-600 text-xs">
         <h4 className="font-bold text-sky-400">Satellite View (Simulated)</h4>
         <p className="text-slate-300">Extraction Confidence: {(95 + Math.random()*4).toFixed(1)}%</p>
         <p className="text-slate-300">Sensor: Sentinel-2 MSI</p>
         <div className="mt-2 flex items-center gap-2">
            <span className="w-3 h-3 bg-blue-500 rounded-sm inline-block"></span>
            <span>Water Body</span>
         </div>
      </div>
    </div>
  );
};

export default MapVisualizer;

import React from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend } from 'recharts';
import { SeasonalData } from '../types';

interface VolumeChartProps {
  data: SeasonalData[];
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-slate-800 border border-slate-600 p-3 rounded shadow-lg text-sm">
        <p className="text-slate-200 font-bold">{label}</p>
        <p className="text-sky-400">Volume: {payload[0].value} MCM</p>
        <p className="text-indigo-400">Rainfall: {payload[1].value} mm</p>
      </div>
    );
  }
  return null;
};

const VolumeChart: React.FC<VolumeChartProps> = ({ data }) => {
  // Format data for chart
  const chartData = data.map(d => ({
    name: `${d.season.substring(0,3)} '${d.year.toString().slice(2)}`,
    Volume: d.volume,
    Rainfall: d.rainfall
  }));

  return (
    <div className="w-full h-64 bg-slate-900/50 rounded-xl p-4 border border-slate-800">
      <h3 className="text-sm font-semibold text-slate-400 mb-4">Historical Storage & Rainfall Trends</h3>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
          <defs>
            <linearGradient id="colorVol" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#38bdf8" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#38bdf8" stopOpacity={0}/>
            </linearGradient>
            <linearGradient id="colorRain" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#818cf8" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#818cf8" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
          <XAxis dataKey="name" stroke="#94a3b8" fontSize={10} tickMargin={10} />
          <YAxis stroke="#94a3b8" fontSize={10} />
          <Tooltip content={<CustomTooltip />} />
          <Legend wrapperStyle={{fontSize: '12px', paddingTop: '10px'}}/>
          <Area type="monotone" dataKey="Volume" stroke="#38bdf8" fillOpacity={1} fill="url(#colorVol)" strokeWidth={2} />
          <Area type="monotone" dataKey="Rainfall" stroke="#818cf8" fillOpacity={1} fill="url(#colorRain)" strokeWidth={2} />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default VolumeChart;

import React, { useState, useEffect } from 'react';
import { generateHydrologicalReport } from '../services/geminiService';
import { AIAnalysisResult, Reservoir, SeasonalData } from '../types';
import { Bot, Loader2, AlertTriangle, CheckCircle, AlertOctagon } from 'lucide-react';

interface AIInsightsProps {
  reservoir: Reservoir;
  currentData: SeasonalData;
  history: SeasonalData[];
}

const AIInsights: React.FC<AIInsightsProps> = ({ reservoir, currentData, history }) => {
  const [analysis, setAnalysis] = useState<AIAnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);

  const handleGenerateReport = async () => {
    setLoading(true);
    try {
      const result = await generateHydrologicalReport(reservoir, currentData, history);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  // Auto-generate on mount or change only if user opts in? 
  // Better to let user click to save API calls in this demo, but we can also auto-run.
  // Let's keep it manual for interactivity.

  const getRiskIcon = (level: string) => {
    switch (level) {
      case 'Critical': return <AlertOctagon className="text-red-500" />;
      case 'High': return <AlertTriangle className="text-orange-500" />;
      case 'Moderate': return <AlertTriangle className="text-yellow-500" />;
      default: return <CheckCircle className="text-green-500" />;
    }
  };

  const getRiskColor = (level: string) => {
    switch (level) {
      case 'Critical': return 'bg-red-950/50 border-red-900 text-red-200';
      case 'High': return 'bg-orange-950/50 border-orange-900 text-orange-200';
      case 'Moderate': return 'bg-yellow-950/30 border-yellow-900 text-yellow-200';
      default: return 'bg-green-950/30 border-green-900 text-green-200';
    }
  };

  return (
    <div className="bg-slate-900/50 border border-slate-800 rounded-xl p-6 h-full flex flex-col">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold flex items-center gap-2 text-slate-100">
          <Bot className="text-purple-400" />
          AI Hydrologist
        </h3>
        <button
          onClick={handleGenerateReport}
          disabled={loading}
          className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-lg text-sm transition-colors flex items-center gap-2"
        >
          {loading ? <Loader2 className="animate-spin w-4 h-4" /> : "Generate Report"}
        </button>
      </div>

      {!analysis && !loading && (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 text-sm text-center">
          <Bot className="w-12 h-12 mb-3 opacity-20" />
          <p>Click "Generate Report" to analyze water spread, volume anomalies, and predict risks using Gemini models.</p>
        </div>
      )}

      {loading && (
        <div className="flex-1 flex items-center justify-center">
             <div className="flex flex-col items-center">
                <Loader2 className="w-8 h-8 text-indigo-500 animate-spin mb-2" />
                <p className="text-xs text-indigo-400 animate-pulse">Processing bathymetric & satellite data...</p>
             </div>
        </div>
      )}

      {analysis && !loading && (
        <div className="animate-fade-in space-y-4">
          <div className={`p-4 rounded-lg border flex items-start gap-3 ${getRiskColor(analysis.riskLevel)}`}>
            {getRiskIcon(analysis.riskLevel)}
            <div>
              <span className="text-xs font-bold uppercase tracking-wider opacity-70">Risk Assessment</span>
              <p className="font-bold text-lg">{analysis.riskLevel} Risk</p>
            </div>
          </div>

          <div className="space-y-1">
            <h4 className="text-xs font-bold text-slate-400 uppercase">Executive Summary</h4>
            <p className="text-sm text-slate-300 leading-relaxed">{analysis.summary}</p>
          </div>

          <div className="space-y-1 pt-2 border-t border-slate-700/50">
             <h4 className="text-xs font-bold text-slate-400 uppercase">Operational Recommendation</h4>
             <p className="text-sm font-medium text-sky-300">{analysis.recommendation}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default AIInsights;

