          {/* Left Column: Map & Key Stats (8 cols) */}
          <div className="lg:col-span-8 flex flex-col gap-6 h-full">
            {/* Map Container */}
            <div className="flex-1 bg-slate-900 rounded-xl relative group">
                <MapVisualizer reservoir={selectedReservoir} data={currentData} />
            </div>

            {/* Quick Stats Strip */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
               <StatCard 
                 label="Water Level" 
                 value={`${currentData.waterLevel} m`} 
                 sub={`Full: ${selectedReservoir.fullLevel} m`}
