const MapUpdater: React.FC<{ center: [number, number] }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    if (center && Number.isFinite(center[0]) && Number.isFinite(center[1])) {
       map.flyTo(center, 12, { duration: 2 });
    }
  }, [center, map]);
  return null;
};

