import React, { useEffect, useMemo } from 'react';
import { MapContainer, TileLayer, Polygon, CircleMarker, Popup, useMap, LayersControl, Marker, Tooltip } from 'react-leaflet';
import { Reservoir, SeasonalData } from '../types';
import { generateWaterPolygon } from '../services/mockData';
import L from 'leaflet';

// Fix for default Leaflet icons in React
// @ts-ignore
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png',
});

interface MapVisualizerProps {
  reservoir: Reservoir;
  data: SeasonalData;
  label?: string; // Optional label for comparison mode
}

const isValidCoordinate = (coord: any): coord is [number, number] => {
  return Array.isArray(coord) && 
         coord.length === 2 && 
         Number.isFinite(coord[0]) && 
         Number.isFinite(coord[1]);
};

const MapUpdater: React.FC<{ center: [number, number] }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    if (isValidCoordinate(center)) {
       map.flyTo(center, 12, { duration: 2 });
    }
  }, [center, map]);
  return null;
};

const MapVisualizer: React.FC<MapVisualizerProps> = ({ reservoir, data, label }) => {

  // Guard against undefined/bad reservoir data
  const safeReservoirLocation = useMemo((): [number, number] => {
    if (reservoir && isValidCoordinate(reservoir.location)) {
        return reservoir.location;
    }
    return [13.0, 80.0]; // Default fallback
  }, [reservoir]);

  // Derived inlet location with strict validation
  const inletLocation = useMemo((): [number, number] | null => {
    if (!isValidCoordinate(safeReservoirLocation)) return null;
    const lat = safeReservoirLocation[0] + 0.015;
    const lng = safeReservoirLocation[1] - 0.015;
    if (Number.isFinite(lat) && Number.isFinite(lng)) {
        return [lat, lng];
    }
    return null;
  }, [safeReservoirLocation]);

  const waterPolygon = useMemo(() => {
    if (!data || typeof data.volume !== 'number' || !reservoir || !reservoir.maxCapacity) return [];

    // Additional safety check for location
    if (!isValidCoordinate(safeReservoirLocation)) {
        return [];
    }

    let volPct = (data.volume / reservoir.maxCapacity) * 100;
    if (!Number.isFinite(volPct)) volPct = 0;

    const poly = generateWaterPolygon(safeReservoirLocation, volPct);

    // Filter out any potential invalid points
    return poly.filter(p => isValidCoordinate(p));
  }, [reservoir, data, safeReservoirLocation]);

  const volumePercentage = useMemo(() => {
    if (!data?.volume || !reservoir?.maxCapacity) return 0;
    return (data.volume / reservoir.maxCapacity) * 100;
  }, [data, reservoir]);

  const mapOptions = useMemo(() => {
    let fillColor, strokeColor;

    // Gradient: Lighter blues for low capacity, Darker/Deep blues for high capacity
    if (volumePercentage >= 80) {
      fillColor = '#1e40af'; // blue-800 (High Depth/Volume)
      strokeColor = '#172554'; // blue-950
    } else if (volumePercentage >= 60) {
      fillColor = '#2563eb'; // blue-600
      strokeColor = '#1e3a8a'; // blue-900
    } else if (volumePercentage >= 40) {
      fillColor = '#3b82f6'; // blue-500
      strokeColor = '#1d4ed8'; // blue-700
    } else if (volumePercentage >= 20) {
      fillColor = '#60a5fa'; // blue-400
      strokeColor = '#2563eb'; // blue-600
    } else {
      fillColor = '#93c5fd'; // blue-300 (Shallow)
      strokeColor = '#3b82f6'; // blue-500
    }

    return {
      fillColor,
      fillOpacity: 0.65,
      color: strokeColor,
      weight: 2
    };
  }, [volumePercentage]);

  return (
    <div className="h-full w-full rounded-xl overflow-hidden border border-slate-700 shadow-2xl relative">
      <MapContainer 
        key={`${reservoir?.id}-${data?.year}-${data?.season}`} 
        center={safeReservoirLocation} 
        zoom={12} 
        style={{ height: '100%', width: '100%', background: '#0f172a' }}
        scrollWheelZoom={true}
      >
        <LayersControl position="topright">
          <LayersControl.BaseLayer checked name="Dark Matter (Data)">
            <TileLayer
              attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
              url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
            />
          </LayersControl.BaseLayer>
          <LayersControl.BaseLayer name="Satellite (Esri)">
            <TileLayer
              attribution='Tiles &copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EGP, and the GIS User Community'
              url="https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}"
            />
          </LayersControl.BaseLayer>
          <LayersControl.BaseLayer name="OpenStreetMap">
             <TileLayer
              attribution='&copy; OpenStreetMap contributors'
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />
          </LayersControl.BaseLayer>
        </LayersControl>

        <MapUpdater center={safeReservoirLocation} />

        {waterPolygon.length > 0 && (
          <Polygon positions={waterPolygon as any} pathOptions={mapOptions}>
             <Popup>
              <div className="text-slate-900 text-sm">
                <strong className="text-base">{reservoir?.name || 'Reservoir'}</strong>
                <hr className="my-1 border-slate-300"/>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                   <span>Water Area:</span> <span className="font-mono">{data?.surfaceArea} km²</span>
                   <span>Volume:</span> <span className="font-mono">{data?.volume} MCM</span>
                   <span>Capacity:</span> <span className="font-mono">{Math.round(volumePercentage)}%</span>
                   <span>Level:</span> <span className="font-mono">{data?.waterLevel} m</span>
                </div>
              </div>
            </Popup>
          </Polygon>
        )}

        {isValidCoordinate(safeReservoirLocation) && (
          <CircleMarker center={safeReservoirLocation} radius={4} pathOptions={{color: 'white', opacity: 0.8, fillColor: 'white', fillOpacity: 1}}>
             <Tooltip direction="top" offset={[0, -5]} opacity={1} permanent>
                Depth Probe
             </Tooltip>
          </CircleMarker>
        )}

        {inletLocation && isValidCoordinate(inletLocation) && (
          <Marker position={inletLocation}>
               <Popup>
                 <div className="text-slate-900">
                   <strong>Primary Inflow</strong><br/>
                   Flow Rate: {(data?.rainfall ? (data.rainfall * 0.2).toFixed(1) : '0.0')} m³/s
                 </div>
               </Popup>
          </Marker>
        )}

      </MapContainer>

      {/* Overlay Info */}
      <div className="absolute top-4 left-14 z-[400] bg-slate-900/90 backdrop-blur-md p-3 rounded-lg border border-slate-600 text-xs shadow-xl print:hidden">
         {label && (
             <div className="mb-2 pb-2 border-b border-slate-700">
                 <h4 className="font-bold text-white uppercase tracking-wider">{label}</h4>
             </div>
         )}
         <h4 className="font-bold text-sky-400 flex items-center gap-2">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-sky-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-sky-500"></span>
            </span>
            Live Satellite Feed
         </h4>
         <p className="text-slate-300 mt-1">Source: Sentinel-2 (L2A)</p>
         <p className="text-slate-300">Band Combination: NDWI</p>
         <div className="flex items-center gap-2 mt-2 pt-2 border-t border-slate-700">
            <div className="flex flex-col gap-1 w-full">
                <span className="text-[10px] text-slate-400">Water Intensity Index</span>
                <div className="h-1.5 w-full bg-gradient-to-r from-blue-300 via-blue-500 to-blue-900 rounded-full"></div>
                <div className="flex justify-between text-[8px] text-slate-500">
                   <span>Low</span>
                   <span>High</span>
                </div>
            </div>
         </div>
      </div>
    </div>
  );
};

export default MapVisualizer;

import { GoogleGenAI, Type } from "@google/genai";
import { SeasonalData, Reservoir, AIAnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are an expert Water Intelligence AI acting as the reasoning, decision-making, and explainability core of an AI-powered geospatial system for surface water monitoring.

Your role is to act as the reasoning, decision-making, explainability, and reporting engine for the app.
You DO NOT perform pixel-level image segmentation.
You DO analyze and reason over outputs from ML models (CNN, Random Forest, LSTM), physical and hydrological constraints, geospatial statistics, and time-series trends.

Your outputs must be structured, deterministic where possible, and suitable for scientific reports and dashboards.

CORE RESPONSIBILITIES:
1. EXPLAINABLE AI (XAI): Explain why a region is classified as water/non-water using spectral indices (NDWI, MNDWI).
2. RISK ASSESSMENT: Assess flood and drought risks based on storage anomalies.
3. WATER LOSS ATTRIBUTION: Estimate evaporation vs extraction vs seepage.
4. RESERVOIR HEALTH: Evaluate overall hydrological health.
5. KNOWLEDGE-GUIDED AI: Ensure physical realism in all outputs (e.g., volume cannot exceed capacity).

SPECIFIC PREDICTION LOGIC:
- FLOOD RISK MODEL: 
  - IF (Capacity > 85% AND Rainfall_Anomaly > +20%) -> High Probability (>70%).
  - IF (Capacity > 95%) -> Critical Probability (>90%).
  - Return a probability score (0-100).

- DROUGHT SEVERITY MODEL (SPI Proxy): 
  - IF (Seasonal_Volume_Anomaly < -20%) -> Moderate.
  - IF (Seasonal_Volume_Anomaly < -40%) -> Severe.
  - IF (Seasonal_Volume_Anomaly < -60%) -> Extreme.
  - Return severity class.

Provide decisions, explanations, confidence estimates, risk classification, and analytical insights suitable for decision-makers.
`;

export const generateHydrologicalReport = async (
  reservoir: Reservoir,
  currentData: SeasonalData,
  historicalTrend: SeasonalData[]
): Promise<AIAnalysisResult> => {

  // 1. Calculate Seasonal Baselines (More accurate than global average)
  const seasonalHistory = historicalTrend.filter(d => d.season === currentData.season);
  const seasonalAvgVolume = seasonalHistory.reduce((acc, curr) => acc + curr.volume, 0) / (seasonalHistory.length || 1);
  const seasonalAvgRain = seasonalHistory.reduce((acc, curr) => acc + curr.rainfall, 0) / (seasonalHistory.length || 1);

  // 2. Calculate Anomalies
  const volumeAnomaly = ((currentData.volume - seasonalAvgVolume) / (seasonalAvgVolume || 1)) * 100;
  const rainfallAnomaly = ((currentData.rainfall - seasonalAvgRain) / (seasonalAvgRain || 1)) * 100;
  const percentFull = (currentData.volume / reservoir.maxCapacity) * 100;

  const prompt = `
    Analyze the following satellite-derived hydrological data for ${reservoir.name}.

    Context:
    - Description: ${reservoir.description}
    - Max Capacity: ${reservoir.maxCapacity} MCM
    - Full Level: ${reservoir.fullLevel} m
    - Catchment: ${reservoir.catchmentArea} sq km

    Current Data (${currentData.season} ${currentData.year}):
    - Volume: ${currentData.volume} MCM (${percentFull.toFixed(1)}% Full)
    - Surface Area: ${currentData.surfaceArea} sq km (Sentinel-2 NDWI)
    - Rainfall: ${currentData.rainfall} mm

    Statistical Anomalies (vs ${currentData.season} Baseline):
    - Volume Anomaly: ${volumeAnomaly > 0 ? '+' : ''}${volumeAnomaly.toFixed(1)}% ${volumeAnomaly < -20 ? '(Significant Deficit)' : ''}
    - Rainfall Anomaly: ${rainfallAnomaly > 0 ? '+' : ''}${rainfallAnomaly.toFixed(1)}% ${rainfallAnomaly > 50 ? '(Heavy Excess)' : ''}

    Task:
    1. Determine current Operational Risk Level.
    2. FLOOD MODEL: Calculate Flood Probability % (0-100) using capacity ${percentFull.toFixed(1)}% and rain anomaly ${rainfallAnomaly.toFixed(1)}%.
    3. DROUGHT MODEL: Classify Drought Severity based on volume deficit ${volumeAnomaly.toFixed(1)}%.
    4. Generate a short 3-month hydrological forecast.
    5. Provide an Operational Recommendation.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            riskLevel: { type: Type.STRING, enum: ['Low', 'Moderate', 'High', 'Critical'] },
            floodProbability: { type: Type.INTEGER, description: "Probability of flood in next 3 months (0-100)" },
            droughtSeverity: { type: Type.STRING, enum: ['Normal', 'Moderate', 'Severe', 'Extreme'] },
            forecast: { type: Type.STRING, description: "Short term predictive outlook" },
            summary: { type: Type.STRING },
            recommendation: { type: Type.STRING }
          },
          required: ['riskLevel', 'floodProbability', 'droughtSeverity', 'forecast', 'summary', 'recommendation']
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AIAnalysisResult;
    }
    throw new Error("Empty response from AI");
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      riskLevel: 'Moderate',
      floodProbability: 0,
      droughtSeverity: 'Normal',
      forecast: 'Prediction unavailable due to data service interruption.',
      summary: 'AI analysis unavailable due to connectivity issues. Standard monitoring protocols apply.',
      recommendation: 'Continue manual observation and log data points.'
    };
  }
};

