// Helper to generate a rough polygon (circle-ish) for the map based on volume
export const generateWaterPolygon = (center: [number, number], volumePct: number) => {
  if (!center || !Number.isFinite(center[0]) || !Number.isFinite(center[1])) {
    return [];
  }

  const points = [];
  const sides = 20;
  // Adjusted radius scaling for better visibility of these specific lakes
  // Ensure we don't multiply by NaN or Infinity
  const safeVolPct = Number.isFinite(volumePct) ? volumePct : 0;
  const baseRadius = 0.015 * (safeVolPct / 100); 

  for (let i = 0; i < sides; i++) {
    const angle = (i * 360) / sides;
    const rad = (angle * Math.PI) / 180;
    // Add some noise to make it look organic
    const r = baseRadius * (0.8 + Math.random() * 0.4); 
    const lat = center[0] + r * Math.cos(rad);
    const lng = center[1] + r * Math.sin(rad) * 1.2; // Slight oval

    // Safety check: only push if coordinates are numbers
    if (Number.isFinite(lat) && Number.isFinite(lng)) {
      points.push([lat, lng]);
    }
  }
  return points;
};

// Generate historical data
export const getHistoricalData = (reservoirId: string): SeasonalData[] => {
  const data: SeasonalData[] = [];
  const startYear = 2020;
  const seasons: SeasonalData['season'][] = ['Winter', 'Summer', 'Monsoon', 'Post-Monsoon'];

  // Deterministic "random" based on ID
  // Guard against empty strings to prevent NaN from charCodeAt(-1)
  const seed = (reservoirId && reservoirId.length > 0) ? reservoirId.charCodeAt(reservoirId.length - 1) : 42;

  for (let year = startYear; year <= 2024; year++) {
    seasons.forEach((season, index) => {
      let baseVol = 50; // %
      if (season === 'Monsoon') baseVol = 90;
      if (season === 'Post-Monsoon') baseVol = 80;
      if (season === 'Winter') baseVol = 60;
      if (season === 'Summer') baseVol = 30;

      // Trend: slowly drying up or varying
      const trend = (year - startYear) * (seed % 2 === 0 ? -2 : 1); 
      const noise = (Math.sin(year * index) * 10);

      const volume = Math.max(10, Math.min(100, baseVol + trend + noise));

      // Derived metrics
      const reservoir = RESERVOIRS.find(r => r.id === reservoirId);
      const maxVol = reservoir?.maxCapacity || 100;
      const fullLevel = reservoir?.fullLevel || 20;

      const actualVolume = Math.round((volume / 100) * maxVol);
      // Surface area relative to volume (simplified physics)
      const surfaceArea = Math.round((actualVolume / maxVol) * 15 * 100) / 100; 

      const waterLevel = Math.round((volume / 100) * fullLevel * 10) / 10;
      const rainfall = season === 'Monsoon' ? 800 + noise * 10 : 50 + noise;

      data.push({
        season,
        year,
        volume: actualVolume,
        waterLevel,
        surfaceArea,
        rainfall: Math.max(0, Math.round(rainfall)),
        cloudCover: season === 'Monsoon' ? 80 : 10
      });
    });
  }
  return data;
};

import axios from 'axios';
import { SeasonalData, AIAnalysisResult } from '../types';

const API_BASE_URL = 'http://localhost:8000';

export interface BackendSatelliteResponse {
    source: string;
    data: {
        surface_area_sqkm: number;
        volume_mcm: number;
        water_level_m: number;
        fill_percentage: number;
        cloud_cover_pct: number;
        satellite_pass: string;
    }
}

export const api = {
    /**
     * Fetches real-time satellite analysis from Python Backend (GEE Pipeline)
     */
    getSatelliteData: async (
        reservoirId: string, 
        lat: number, 
        lng: number, 
        season: string,
        maxCapacity: number
    ): Promise<BackendSatelliteResponse> => {
        try {
            const response = await axios.post(`${API_BASE_URL}/api/satellite`, {
                reservoir_id: reservoirId,
                lat,
                lng,
                season,
                max_capacity: maxCapacity
            });
            return response.data;
        } catch (error) {
            console.error("Backend Connection Error:", error);
            throw error;
        }
    },

    /**
     * Runs ML Forecast (LSTM) on the backend
     */
    getForecast: async (historicalVolumes: number[]): Promise<number> => {
        try {
            const response = await axios.post(`${API_BASE_URL}/api/ml/forecast`, historicalVolumes);
            return response.data.next_season_volume_prediction;
        } catch (error) {
            console.error("ML Forecast Error:", error);
            return 0;
        }
    },

    /**
     * Detects Anomaly using Backend Isolation Forest
     */
    checkAnomaly: async (currentVol: number, historicalAvg: number) => {
        try {
            const response = await axios.post(`${API_BASE_URL}/api/ml/anomaly`, null, {
                params: { current_vol: currentVol, historical_avg: historicalAvg }
            });
            return response.data;
        } catch (error) {
            console.error("Anomaly Detection Error:", error);
            return { is_anomaly: false };
        }
    },

    /**
     * Secure Gemini Call
     */
    generateReport: async (payload: any): Promise<AIAnalysisResult> => {
         try {
            const response = await axios.post(`${API_BASE_URL}/api/gemini/analyze`, payload);
            return response.data;
        } catch (error) {
            console.error("AI Report Error:", error);
            throw error;
        }
    },

    /**
     * Send Feedback for Retraining
     */
    sendFeedback: async (feedback: any) => {
        return axios.post(`${API_BASE_URL}/api/ml/retrain`, feedback);
    }
};

import { SeasonalData, Reservoir, AIAnalysisResult } from "../types";
import { api } from "./api";

export const generateHydrologicalReport = async (
  reservoir: Reservoir,
  currentData: SeasonalData,
  historicalTrend: SeasonalData[]
): Promise<AIAnalysisResult> => {

  // Calculate Seasonal Statistics
  const seasonalHistory = historicalTrend.filter(d => d.season === currentData.season);
  const seasonalAvgVolume = seasonalHistory.reduce((acc, curr) => acc + curr.volume, 0) / (seasonalHistory.length || 1);
  const seasonalAvgRain = seasonalHistory.reduce((acc, curr) => acc + curr.rainfall, 0) / (seasonalHistory.length || 1);

  // Anomalies
  const volumeAnomaly = ((currentData.volume - seasonalAvgVolume) / (seasonalAvgVolume || 1)) * 100;
  const rainfallAnomaly = ((currentData.rainfall - seasonalAvgRain) / (seasonalAvgRain || 1)) * 100;

  // Construct Payload for Backend
  const payload = {
    reservoir_name: reservoir.name,
    current_volume: currentData.volume,
    max_capacity: reservoir.maxCapacity,
    rainfall_anomaly: rainfallAnomaly,
    season: currentData.season
  };

  try {
    // Call the Secure Python Backend
    const result = await api.generateReport(payload);
    return result;
  } catch (error) {
    console.error("Backend API Error:", error);
    // Fallback if backend is down
    return {
      riskLevel: 'Moderate',
      floodProbability: 0,
      droughtSeverity: 'Normal',
      forecast: 'Backend connection failed. Using cached physics data.',
      summary: 'Unable to reach AI inference engine. Please check connection.',
      recommendation: 'Use manual calculations.'
    };
  }
};

