interface MapVisualizerProps {
  reservoir: Reservoir;
  data: SeasonalData;
  label?: string; // Optional label for comparison mode
  isLive?: boolean; // Status of the data feed
}

const DEFAULT_CENTER: [number, number] = [13.0, 80.0];

const isValidCoordinate = (coord: any): coord is [number, number] => {
  return Array.isArray(coord) && 
         coord.length === 2 && 
         typeof coord[0] === 'number' && Number.isFinite(coord[0]) && !Number.isNaN(coord[0]) &&
         typeof coord[1] === 'number' && Number.isFinite(coord[1]) && !Number.isNaN(coord[1]);
};

const MapUpdater: React.FC<{ center: [number, number] }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    if (isValidCoordinate(center)) {
       // Debounce flyTo or handle potential animation conflicts if needed
       map.flyTo(center, 12, { duration: 2 });
    }
  }, [center, map]);
  return null;
};

const MapVisualizer: React.FC<MapVisualizerProps> = ({ reservoir, data, label, isLive = false }) => {
  const [layerOpacity, setLayerOpacity] = useState(0.65);

  // Guard against undefined/bad reservoir data with strict fallback
  const safeReservoirLocation = useMemo((): [number, number] => {
    if (reservoir && isValidCoordinate(reservoir.location)) {
        return reservoir.location;
    }
    return DEFAULT_CENTER;
  }, [reservoir]);

  // Derived inlet location with strict validation
  const inletLocation = useMemo((): [number, number] | null => {
    if (!isValidCoordinate(safeReservoirLocation)) return null;
    const lat = safeReservoirLocation[0] + 0.015;
    const lng = safeReservoirLocation[1] - 0.015;
    if (Number.isFinite(lat) && Number.isFinite(lng)) {
        return [lat, lng];
    }
    return null;
  }, [safeReservoirLocation]);

  const waterPolygon = useMemo(() => {
    if (!data || typeof data.volume !== 'number' || !reservoir || !reservoir.maxCapacity) return [];

    // Additional safety check for location
    if (!isValidCoordinate(safeReservoirLocation)) {
        return [];
    }

    let volPct = (data.volume / reservoir.maxCapacity) * 100;
    // Ensure volPct is a finite number
    if (!Number.isFinite(volPct) || Number.isNaN(volPct)) volPct = 0;

    const poly = generateWaterPolygon(safeReservoirLocation, volPct);

    // Filter out any potential invalid points to satisfy Leaflet
    return poly.filter(p => isValidCoordinate(p));
  }, [reservoir, data, safeReservoirLocation]);

  const volumePercentage = useMemo(() => {
    if (!data?.volume || !reservoir?.maxCapacity) return 0;
    const val = (data.volume / reservoir.maxCapacity) * 100;
    return Number.isFinite(val) ? val : 0;
  }, [data, reservoir]);

  const mapOptions = useMemo(() => {
    let fillColor, strokeColor;

    // Gradient: Lighter blues for low capacity, Darker/Deep blues for high capacity
    if (volumePercentage >= 80) {
      fillColor = '#1e40af'; // blue-800 (High Depth/Volume)
      strokeColor = '#172554'; // blue-950
    } else if (volumePercentage >= 60) {
      fillColor = '#2563eb'; // blue-600
      strokeColor = '#1e3a8a'; // blue-900
    } else if (volumePercentage >= 40) {
      fillColor = '#3b82f6'; // blue-500
      strokeColor = '#1d4ed8'; // blue-700
    } else if (volumePercentage >= 20) {
      fillColor = '#60a5fa'; // blue-400
      strokeColor = '#2563eb'; // blue-600
    } else {
      fillColor = '#93c5fd'; // blue-300 (Shallow)
      strokeColor = '#3b82f6'; // blue-500
    }

    return {
      fillColor,
      fillOpacity: layerOpacity, // Use dynamic opacity
      color: strokeColor,
      weight: 2
    };
  }, [volumePercentage, layerOpacity]);

  return (
    <div className="h-full w-full rounded-xl overflow-hidden border border-slate-700 shadow-2xl relative">
      <MapContainer 
        key={`${reservoir?.id}-${data?.year}-${data?.season}`} 
        center={safeReservoirLocation} 
        zoom={12} 
        style={{ height: '100%', width: '100%', background: '#0f172a' }}
        scrollWheelZoom={true}
      >
        <LayersControl position="topright">
          <LayersControl.BaseLayer checked name="Dark Matter (Data)">
            <TileLayer
              attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
              url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
            />
          </LayersControl.BaseLayer>
          <LayersControl.BaseLayer name="Satellite (Esri)">
            <TileLayer
              attribution='Tiles &copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EGP, and the GIS User Community'
              url="https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}"
            />
          </LayersControl.BaseLayer>
          <LayersControl.BaseLayer name="OpenStreetMap">
             <TileLayer
              attribution='&copy; OpenStreetMap contributors'
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />
          </LayersControl.BaseLayer>
        </LayersControl>

        <MapUpdater center={safeReservoirLocation} />

        {waterPolygon.length > 0 && (
          <Polygon positions={waterPolygon as any} pathOptions={mapOptions}>
             <Popup>
              <div className="text-slate-900 text-sm">
                <strong className="text-base">{reservoir?.name || 'Reservoir'}</strong>
                <hr className="my-1 border-slate-300"/>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                   <span>Water Area:</span> <span className="font-mono">{data?.surfaceArea} km²</span>
                   <span>Volume:</span> <span className="font-mono">{data?.volume} MCM</span>
                   <span>Capacity:</span> <span className="font-mono">{Math.round(volumePercentage)}%</span>
                   <span>Level:</span> <span className="font-mono">{data?.waterLevel} m</span>
                </div>
              </div>
            </Popup>
          </Polygon>
        )}

        {isValidCoordinate(safeReservoirLocation) && (
          <CircleMarker center={safeReservoirLocation} radius={4} pathOptions={{color: 'white', opacity: 0.8, fillColor: 'white', fillOpacity: 1}}>
             <Tooltip direction="top" offset={[0, -5]} opacity={1} permanent>
                Depth Probe
             </Tooltip>
          </CircleMarker>
        )}

        {inletLocation && isValidCoordinate(inletLocation) && (
          <Marker position={inletLocation}>
               <Popup>
                 <div className="text-slate-900">
                   <strong>Primary Inflow</strong><br/>
                   Flow Rate: {(data?.rainfall ? (data.rainfall * 0.2).toFixed(1) : '0.0')} m³/s
                 </div>
               </Popup>
          </Marker>
        )}

      </MapContainer>

      {/* Overlay Info */}
      <div className="absolute top-4 left-14 z-[400] bg-slate-900/90 backdrop-blur-md p-3 rounded-lg border border-slate-600 text-xs shadow-xl print:hidden w-64">
         {label && (
             <div className="mb-2 pb-2 border-b border-slate-700">
                 <h4 className="font-bold text-white uppercase tracking-wider">{label}</h4>
             </div>
         )}
         <h4 className={`font-bold flex items-center gap-2 ${isLive ? 'text-sky-400' : 'text-orange-400'}`}>
            <span className="relative flex h-2 w-2">
              <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${isLive ? 'bg-sky-400' : 'bg-orange-400'}`}></span>
              <span className={`relative inline-flex rounded-full h-2 w-2 ${isLive ? 'bg-sky-500' : 'bg-orange-500'}`}></span>
            </span>
            {isLive ? 'Live Satellite Feed' : 'Simulated Physics Feed'}
         </h4>
         <p className="text-slate-300 mt-1">Source: {isLive ? 'Sentinel-2 (L2A)' : 'Approximation Model'}</p>

         <div className="mt-3">
             <div className="flex justify-between items-center text-slate-400 mb-1">
                <span className="flex items-center gap-1"><Layers size={10}/> Layer Opacity</span>
                <span className="font-mono">{Math.round(layerOpacity * 100)}%</span>
             </div>
             <input 
                type="range" 
                min="0" 
                max="1" 
                step="0.05"
                value={layerOpacity}
                onChange={(e) => setLayerOpacity(parseFloat(e.target.value))}
                className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer"
             />
         </div>

         <div className="flex items-center gap-2 mt-2 pt-2 border-t border-slate-700">
            <div className="flex flex-col gap-1 w-full">
                <span className="text-[10px] text-slate-400">Water Intensity Index</span>
                <div className="h-1.5 w-full bg-gradient-to-r from-blue-300 via-blue-500 to-blue-900 rounded-full"></div>
                <div className="flex justify-between text-[8px] text-slate-500">
                   <span>Low</span>
                   <span>High</span>
                </div>
            </div>
         </div>
      </div>
    </div>
  );
};

export default MapVisualizer;

import React from 'react';
import { RESERVOIRS } from '../services/mockData';
import { SimulationState, SeasonalData } from '../types';
import { Calendar, Droplets, MapPin, GitCompare, X, ArrowRightLeft, Play, Pause } from 'lucide-react';

interface DashboardControlsProps {
  state: SimulationState;
  onChange: (newState: Partial<SimulationState>) => void;
  availableSeasons: SeasonalData['season'][];
  availableYears: number[];
  isPlaying: boolean;
  onTogglePlay: () => void;
}

const DashboardControls: React.FC<DashboardControlsProps> = ({ 
  state, 
  onChange, 
  availableSeasons, 
  availableYears,
  isPlaying,
  onTogglePlay
}) => {

  const toggleComparison = () => {
    onChange({ 
      isComparisonMode: !state.isComparisonMode,
      // Default comparison to previous year same season if enabling
      compareYear: state.isComparisonMode ? state.compareYear : Math.max(Math.min(...availableYears), state.year - 1),
      compareSeason: state.isComparisonMode ? state.compareSeason : state.season
    });
  };

  const DateSelector = ({ 
    year, 
    season, 
    onYearChange, 
    onSeasonChange, 
    colorClass, 
    label 
  }: { 
    year: number, 
    season: SeasonalData['season'], 
    onYearChange: (y: number) => void, 
    onSeasonChange: (s: SeasonalData['season']) => void,
    colorClass: string,
    label: string
  }) => (
    <div className={`p-3 rounded-lg border ${colorClass} transition-all`}>
      <div className="flex items-center gap-2 mb-2">
         <span className="text-xs font-bold uppercase tracking-wider opacity-70">{label}</span>
      </div>

      {/* Year Slider */}
      <div className="mb-3">
         <div className="flex justify-between items-center mb-1">
            <label className="text-[10px] text-slate-400 flex items-center gap-1"><Calendar size={10}/> Year</label>
            <span className="text-xs font-mono font-bold">{year}</span>
         </div>
         <input 
            type="range" 
            min={Math.min(...availableYears)} 
            max={Math.max(...availableYears)} 
            value={year}
            onChange={(e) => onYearChange(parseInt(e.target.value))}
            className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer"
         />
      </div>

      {/* Season Buttons */}
      <div>
        <label className="block text-[10px] text-slate-400 mb-1 flex items-center gap-1"><Droplets size={10}/> Season</label>
        <div className="flex gap-1 bg-slate-900/50 rounded p-1">
          {availableSeasons.map(s => {
              const isSelected = season === s;
              return (
                  <button
                      key={s}
                      onClick={() => onSeasonChange(s)}
                      className={`flex-1 text-[9px] py-1 rounded transition-colors ${isSelected ? 'bg-slate-200 text-slate-900 font-bold shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                      {s.substring(0, 3)}
                  </button>
              )
          })}
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col gap-4 mb-6">

      <div className="flex flex-col md:flex-row gap-4 items-stretch">

        {/* Reservoir Selector (Always Global) */}
        <div className="md:w-1/3 bg-slate-800/50 border border-slate-700 p-3 rounded-lg flex flex-col justify-center">
          <div className="flex items-center gap-2 mb-2 text-slate-400">
             <MapPin size={16} />
             <span className="text-xs font-semibold uppercase">Target Reservoir</span>
          </div>
          <select 
            className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-sm text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500"
            value={state.selectedReservoirId}
            onChange={(e) => onChange({ selectedReservoirId: e.target.value })}
          >
            {RESERVOIRS.map(r => (
              <option key={r.id} value={r.id}>{r.name}</option>
            ))}
          </select>

          <div className="flex gap-2 mt-4">
              {/* Play / Pause Time-Lapse */}
              <button
                onClick={onTogglePlay}
                className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-xs font-medium transition-all ${
                  isPlaying 
                  ? 'bg-amber-500/20 text-amber-300 border border-amber-500/50 hover:bg-amber-500/30'
                  : 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-900/50'
                }`}
              >
                  {isPlaying ? <Pause size={14} fill="currentColor" /> : <Play size={14} fill="currentColor" />}
                  {isPlaying ? "Pause Time-Lapse" : "Play Time-Lapse"}
              </button>

              {/* Comparison Toggle */}
              <button 
                onClick={toggleComparison}
                className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-xs font-medium transition-all ${
                  state.isComparisonMode 
                  ? 'bg-purple-500/20 text-purple-300 border border-purple-500/50 hover:bg-purple-500/30' 
                  : 'bg-slate-700 text-slate-300 border border-transparent hover:bg-slate-600'
                }`}
              >
                {state.isComparisonMode ? <X size={14} /> : <GitCompare size={14} />}
                {state.isComparisonMode ? "Exit Compare" : "Compare"}
              </button>
          </div>
        </div>

        {/* Date Controls */}
        <div className={`flex-1 grid gap-4 transition-all ${state.isComparisonMode ? 'grid-cols-1 md:grid-cols-2' : 'grid-cols-1'}`}>

           {/* Primary Controls */}
           <DateSelector 
              label="Primary View (Left Map)"
              year={state.year}
              season={state.season}
              onYearChange={(y) => onChange({ year: y })}
              onSeasonChange={(s) => onChange({ season: s })}
              colorClass="bg-slate-800/50 border-slate-700"
           />

           {/* Comparison Controls (Conditional) */}
           {state.isComparisonMode && (
             <DateSelector 
                label="Comparison View (Right Map)"
                year={state.compareYear}
                season={state.compareSeason}
                onYearChange={(y) => onChange({ compareYear: y })}
                onSeasonChange={(s) => onChange({ compareSeason: s })}
                colorClass="bg-purple-900/10 border-purple-500/30 relative"
             />
           )}

           {!state.isComparisonMode && (
              <div className="hidden md:flex flex-col items-center justify-center border border-dashed border-slate-700 rounded-lg text-slate-500 text-xs">
                 <ArrowRightLeft size={24} className="mb-2 opacity-50"/>
                 Enable Comparison Mode to view historical changes side-by-side
              </div>
           )}

        </div>
      </div>
    </div>
  );
};

export default DashboardControls;

import React, { useState, useMemo, useEffect } from 'react';
import { RESERVOIRS, getHistoricalData } from './services/mockData';
import { SimulationState, AIAnalysisResult, SeasonalData } from './types';
import { generateHydrologicalReport } from './services/geminiService';
import { api } from './services/api';
import MapVisualizer from './components/MapVisualizer';
import VolumeChart from './components/VolumeChart';
import AIInsights from './components/AIInsights';
import DashboardControls from './components/DashboardControls';
import ModelFeedback from './components/ModelFeedback';
import { Waves, BarChart3, Info, Download, Mountain, Timer, Loader2, Wifi, WifiOff } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<SimulationState>({
    selectedReservoirId: RESERVOIRS[0].id,
    year: 2024,
    season: 'Post-Monsoon',
    isComparisonMode: false,
    compareYear: 2023,
    compareSeason: 'Post-Monsoon'
  });

  const [aiAnalysis, setAiAnalysis] = useState<AIAnalysisResult | null>(null);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [backendStatus, setBackendStatus] = useState<'online'|'offline'>('offline');
  const [isPlaying, setIsPlaying] = useState(false);

  // Real-time fetched data state
  const [liveData, setLiveData] = useState<Partial<SeasonalData> | null>(null);
  const [mlForecast, setMlForecast] = useState<number | null>(null);
  const [isLoadingLive, setIsLoadingLive] = useState(false);

  const selectedReservoir = useMemo(() => 
    RESERVOIRS.find(r => r.id === state.selectedReservoirId) || RESERVOIRS[0], 
  [state.selectedReservoirId]);

  const historicalData = useMemo(() => 
    getHistoricalData(selectedReservoir.id), 
  [selectedReservoir.id]);

  const availableYears = useMemo(() => Array.from(new Set(historicalData.map(d => d.year))).sort(), [historicalData]);
  const availableSeasons = ['Winter', 'Summer', 'Monsoon', 'Post-Monsoon'] as const;

  // Base physics data (fallback)
  const baseData = useMemo(() => 
    historicalData.find(d => d.year === state.year && d.season === state.season) || historicalData[0],
  [historicalData, state.year, state.season]);

  // Merged Data: Physics + Real Backend Data
  const currentData = useMemo(() => {
    if (!liveData) return baseData;
    return { ...baseData, ...liveData };
  }, [baseData, liveData]);

  const comparisonData = useMemo(() => 
    historicalData.find(d => d.year === state.compareYear && d.season === state.compareSeason) || historicalData[0],
  [historicalData, state.compareYear, state.compareSeason]);

  // --- Time-Lapse Effect ---
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying) {
      interval = setInterval(() => {
        setState(prev => {
          const currentSeasonIdx = availableSeasons.indexOf(prev.season);

          let nextSeasonIdx = currentSeasonIdx + 1;
          let nextYear = prev.year;

          // Advance season
          if (nextSeasonIdx >= availableSeasons.length) {
            nextSeasonIdx = 0;
            nextYear = prev.year + 1;
          }

          // Loop years if end reached
          const maxYear = Math.max(...availableYears);
          const minYear = Math.min(...availableYears);

          if (nextYear > maxYear) {
            nextYear = minYear;
            nextSeasonIdx = 0;
          }

          return {
            ...prev,
            year: nextYear,
            season: availableSeasons[nextSeasonIdx]
          };
        });
      }, 2000); // 2 seconds per frame
    }
    return () => clearInterval(interval);
  }, [isPlaying, availableYears]);


  // --- Effect: Fetch Real Data from Python Backend ---
  useEffect(() => {
    const fetchRealData = async () => {
        setIsLoadingLive(true);
        try {
            // 1. Fetch Satellite/Physics Data
            const satData = await api.getSatelliteData(
                selectedReservoir.id,
                selectedReservoir.location[0],
                selectedReservoir.location[1],
                state.season,
                selectedReservoir.maxCapacity
            );

            // 2. Check for Anomalies (ML)
            await api.checkAnomaly(satData.data.volume_mcm, baseData.volume);

            setLiveData({
                volume: satData.data.volume_mcm,
                surfaceArea: satData.data.surface_area_sqkm,
                waterLevel: satData.data.water_level_m,
                cloudCover: satData.data.cloud_cover_pct
            });

            // 3. Get ML Forecast for Next Season
            const volumes = historicalData.map(d => d.volume);
            const forecastVal = await api.getForecast(volumes);
            setMlForecast(forecastVal);

            // If the source indicates it's a fallback simulation, mark backend as offline
            if (satData.source.includes('Offline')) {
                setBackendStatus('offline');
            } else {
                setBackendStatus('online');
            }

        } catch (e) {
            console.warn("Backend error, defaulting to offline mode.");
            setBackendStatus('offline');
            setLiveData(null);
            setMlForecast(null);
        } finally {
            setIsLoadingLive(false);
        }
    };

    fetchRealData();
  }, [selectedReservoir, state.season, state.year, historicalData, baseData.volume]);


  const handleStateChange = (newState: Partial<SimulationState>) => {
    setState(prev => ({ ...prev, ...newState }));
    // If user interacts manually, stop playing
    if (newState.year || newState.season || newState.selectedReservoirId) {
        setIsPlaying(false);
    }
    setAiAnalysis(null);
  };

  const handleGenerateAI = async () => {
    setIsGeneratingReport(true);
    try {
      const result = await generateHydrologicalReport(selectedReservoir, currentData, historicalData);
      setAiAnalysis(result);
      return result;
    } catch (e) {
      console.error("AI Generation failed:", e);
      return null;
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleDownloadReport = async () => {
    // If analysis is already there, print immediately
    if (aiAnalysis) {
      window.print();
      return;
    }

    // Otherwise generate it first, then print
    const result = await handleGenerateAI();
    if (result) {
      // Give React time to render the new AIInsights component
      setTimeout(() => {
        window.print();
      }, 800);
    } else {
        alert("Report generation failed. Printing without AI insights.");
        window.print();
    }
  };

  const handleFeedbackSubmit = async (feedback: any) => {
    try {
        await api.sendFeedback(feedback);
        console.log("RLHF Feedback sent.");
    } catch (e) {
        // Quietly fail
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500/30">

      {/* Header */}
      <header className="bg-slate-900/50 backdrop-blur-lg border-b border-slate-800 sticky top-0 z-50 print-hidden">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Waves className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-slate-100 tracking-tight">HydroAI</h1>
              <p className="text-xs text-slate-400">Tamil Nadu Reservoir Monitor</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className={`hidden md:flex items-center gap-4 text-xs font-medium ${backendStatus === 'online' ? 'text-green-500' : 'text-orange-500'}`}>
                <span className="flex items-center gap-1">
                    {backendStatus === 'online' ? <Wifi size={14} /> : <WifiOff size={14}/>} 
                    {backendStatus === 'online' ? "Live Backend" : "Simulated Mode"}
                </span>
             </div>
             <button 
                onClick={handleDownloadReport}
                disabled={isGeneratingReport}
                className="flex items-center gap-2 bg-slate-800 hover:bg-slate-700 disabled:opacity-50 text-slate-200 px-3 py-1.5 rounded-md text-sm transition-colors border border-slate-700 active:scale-95"
             >
                {isGeneratingReport ? (
                    <Loader2 size={14} className="animate-spin" />
                ) : (
                    <Download size={14} />
                )}
                {isGeneratingReport ? "Generating..." : "Download Report"}
             </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-6 space-y-6">

        {/* Print Only Header */}
        <div className="hidden print:block mb-8 border-b border-gray-300 pb-4">
            <div className="flex justify-between items-end">
                <div>
                    <h1 className="text-3xl font-bold text-black mb-1">Hydrological Analysis Report</h1>
                    <p className="text-sm text-gray-600">Generated via HydroAI Geospatial System</p>
                </div>
                <div className="text-right text-sm text-gray-500">
                    <p>Date: {new Date().toLocaleDateString()}</p>
                    <p>Ref ID: {selectedReservoir.id.toUpperCase()}-{state.year}-{state.season}</p>
                </div>
            </div>
        </div>

        {/* Controls Layer (Hidden on Print) */}
        <div className="print-hidden">
            <DashboardControls 
              state={state} 
              onChange={handleStateChange}
              availableSeasons={availableSeasons as any}
              availableYears={availableYears}
              isPlaying={isPlaying}
              onTogglePlay={() => setIsPlaying(!isPlaying)}
            />
        </div>

        {/* Dashboard Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-14rem)] min-h-[600px]">

          {/* Left Column: Map & Key Stats (8 cols) */}
          <div className="lg:col-span-8 flex flex-col gap-6 h-full">

            {/* Map Container */}
            <div className={`flex-1 bg-slate-900 rounded-xl relative group min-h-[300px] map-print-container grid gap-4 transition-all duration-500 ${state.isComparisonMode ? 'grid-cols-2' : 'grid-cols-1'}`}>

                {/* Primary Map */}
                <div className="relative h-full w-full">
                   {isLoadingLive && (
                       <div className="absolute inset-0 z-50 bg-slate-950/60 flex items-center justify-center backdrop-blur-sm">
                           <Loader2 className="animate-spin text-indigo-500 w-8 h-8"/>
                       </div>
                   )}
                   <MapVisualizer 
                      reservoir={selectedReservoir} 
                      data={currentData} 
                      isLive={backendStatus === 'online'}
                      label={state.isComparisonMode ? `${state.season} ${state.year} (Primary)` : undefined}
                   />
                </div>

                {/* Comparison Map */}
                {state.isComparisonMode && (
                  <div className="relative h-full w-full border-l-2 border-slate-700/50">
                    <MapVisualizer 
                      reservoir={selectedReservoir} 
                      data={comparisonData} 
                      isLive={false} // Historical comparison is always "simulated" or "stored"
                      label={`${state.compareSeason} ${state.compareYear} (Comparison)`}
                    />
                    <button 
                       onClick={() => handleStateChange({ isComparisonMode: false })}
                       className="absolute top-2 right-2 z-[500] bg-slate-800 text-slate-300 p-1 rounded-full hover:bg-slate-700 shadow-lg"
                    >
                       <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                    </button>
                  </div>
                )}
            </div>

            {/* Quick Stats Strip */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 print:grid-cols-2">
               <StatCard 
                 label="Water Level" 
                 value={`${currentData.waterLevel} m`} 
                 sub={`FRL: ${selectedReservoir.fullLevel} m`}
                 trend={currentData.waterLevel > (selectedReservoir.fullLevel * 0.8) ? 'up' : 'down'}
               />
               <StatCard 
                 label="Surface Area" 
                 value={`${currentData.surfaceArea} km²`} 
                 sub={backendStatus === 'online' ? "Real-time GEE L2A" : "Simulated NDWI"}
                 icon={<Waves size={14} className="text-blue-400"/>}
               />
               <StatCard 
                 label="Storage Vol" 
                 value={`${currentData.volume} MCM`} 
                 sub={`${Math.round((currentData.volume/selectedReservoir.maxCapacity)*100)}% Capacity`}
                 trend="neutral"
               />
                <StatCard 
                 label="Rainfall" 
                 value={`${currentData.rainfall} mm`} 
                 sub={`${state.season} avg`}
                 icon={<BarChart3 size={14} className="text-blue-400"/>}
               />
            </div>

            {/* Reservoir Details Panel */}
            <div className="bg-slate-900/50 border border-slate-800 p-4 rounded-xl stat-card">
                 <h3 className="text-sm font-semibold text-slate-100 mb-3 flex items-center gap-2">
                    <Info size={16} className="text-indigo-400"/>
                    Reservoir Profile: {selectedReservoir.name}
                 </h3>
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
                    <div className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-lg border border-transparent print:border-gray-200">
                        <Mountain size={18} className="text-emerald-500" />
                        <div>
                            <p className="text-slate-400 text-xs">Catchment Area</p>
