import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { MessageCircle, X, Send, Bot, User, Loader2, Sparkles, Minimize2, Maximize2 } from 'lucide-react';
import { Reservoir, SeasonalData } from '../types';

interface HydroChatProps {
  reservoir: Reservoir;
  currentData: SeasonalData;
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

const HydroChat: React.FC<HydroChatProps> = ({ reservoir, currentData }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: `Hello! I'm analyzing ${reservoir.name}. Ask me about volume trends, rainfall correlations, or historical anomalies.` }
  ]);
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen, isThinking]);

  // Reset chat when reservoir changes to avoid stale context
  useEffect(() => {
    setMessages([
        { role: 'model', text: `I've updated my context to ${reservoir.name} (${currentData.season} ${currentData.year}). How can I help?` }
    ]);
  }, [reservoir.id, currentData.year, currentData.season]);

  const handleSend = async () => {
    if (!input.trim() || isThinking) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsThinking(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemContext = `
        You are HydroChat, an AI assistant for a reservoir monitoring dashboard.

        CURRENT CONTEXT:
        Reservoir: ${reservoir.name}
        Location: ${reservoir.location.join(', ')}
        Max Capacity: ${reservoir.maxCapacity} MCM
        Current Season: ${currentData.season} ${currentData.year}
        Current Volume: ${currentData.volume} MCM
        Current Level: ${currentData.waterLevel} m
        Rainfall: ${currentData.rainfall} mm
        Surface Area: ${currentData.surfaceArea} sq km

        ROLE:
        Answer questions about hydrology, this specific reservoir, and water management.
        Keep answers concise (under 100 words) unless asked for details.
        Use Markdown for formatting.
        If asked about "why" volume is high/low, correlate with rainfall and season.
      `;

      // Construct history for context
      // Note: In a real app we would maintain the chat session object properly
      const chatHistory = messages.map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
      }));

      // Initialize chat with system instruction
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
            systemInstruction: systemContext,
        },
        history: chatHistory
      });

      const result = await chat.sendMessageStream({ message: userMsg });

      let fullResponse = "";
      setMessages(prev => [...prev, { role: 'model', text: "" }]);

      for await (const chunk of result) {
        const text = chunk.text;
        if (text) {
          fullResponse += text;
          setMessages(prev => {
            const newMsgs = [...prev];
            newMsgs[newMsgs.length - 1].text = fullResponse;
            return newMsgs;
          });
        }
      }

    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, { role: 'model', text: "I'm having trouble connecting to the satellite uplink (API Error). Please try again." }]);
    } finally {
      setIsThinking(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-lg shadow-indigo-900/50 transition-all hover:scale-110 print-hidden"
      >
        <MessageCircle size={28} />
        <span className="absolute -top-1 -right-1 flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-sky-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-sky-500"></span>
        </span>
      </button>
    );
  }

  return (
    <div className={`fixed z-50 bg-slate-900 border border-slate-700 shadow-2xl transition-all duration-300 flex flex-col print-hidden ${isMinimized ? 'bottom-6 right-6 w-72 h-14 rounded-full overflow-hidden' : 'bottom-6 right-6 w-96 h-[500px] rounded-xl'}`}>

      {/* Header */}
      <div className={`flex items-center justify-between p-4 bg-slate-800 border-b border-slate-700 cursor-pointer ${isMinimized ? 'h-full' : ''}`} onClick={() => isMinimized && setIsMinimized(false)}>
        <div className="flex items-center gap-2">
          <div className="p-1.5 bg-indigo-600 rounded-lg">
             <Sparkles size={16} className="text-white" />
          </div>
          <h3 className="font-bold text-slate-100 text-sm">HydroChat AI</h3>
        </div>
        <div className="flex items-center gap-1">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsMinimized(!isMinimized); }}
            className="p-1 hover:bg-slate-700 rounded text-slate-400"
          >
             {isMinimized ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); setIsOpen(false); setIsMinimized(false); }}
            className="p-1 hover:bg-red-900/50 rounded text-slate-400 hover:text-red-400"
          >
             <X size={16}/>
          </button>
        </div>
      </div>

      {!isMinimized && (
        <>
          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/95 scrollbar-thin">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                {msg.role === 'model' && (
                  <div className="w-6 h-6 rounded-full bg-indigo-900/50 border border-indigo-700 flex items-center justify-center flex-shrink-0 mt-1">
                    <Bot size={14} className="text-indigo-400"/>
                  </div>
                )}
                <div className={`max-w-[85%] rounded-lg p-3 text-sm leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-bl-none'
                }`}>
                  {msg.text ? (
                      // Simple markdown rendering for basic formatting
                      msg.text.split('\n').map((line, i) => (
                          <p key={i} className="mb-1 last:mb-0">{line}</p>
                      ))
                  ) : (
                      <span className="animate-pulse">...</span>
                  )}
                </div>
                {msg.role === 'user' && (
                  <div className="w-6 h-6 rounded-full bg-slate-700 border border-slate-600 flex items-center justify-center flex-shrink-0 mt-1">
                    <User size={14} className="text-slate-300"/>
                  </div>
                )}
              </div>
            ))}

            {isThinking && (
              <div className="flex gap-3 justify-start">
                  <div className="w-6 h-6 rounded-full bg-indigo-900/50 border border-indigo-700 flex items-center justify-center flex-shrink-0 mt-1">
                    <Bot size={14} className="text-indigo-400"/>
                  </div>
                  <div className="bg-slate-800 border border-slate-700 rounded-lg p-3 rounded-bl-none">
                     <Loader2 size={16} className="animate-spin text-indigo-400"/>
                  </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-3 bg-slate-800 border-t border-slate-700">
            <div className="relative">
              <input 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Ask about water levels, trends..."
                className="w-full bg-slate-900 border border-slate-600 text-slate-200 text-sm rounded-lg pl-4 pr-10 py-3 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 placeholder:text-slate-500"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isThinking}
                className="absolute right-2 top-2 p-1.5 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:bg-slate-700 text-white rounded-md transition-colors"
              >
                <Send size={14} />
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default HydroChat;

