  const baseData = useMemo(() => 
    historicalData.find(d => d.year === state.year && d.season === state.season) || historicalData[0],
  [historicalData, state.year, state.season]);

  // Merged Data: Physics + Real Backend Data
  const currentData = useMemo(() => {
    if (!liveData) return baseData;
    return { ...baseData, ...liveData } as SeasonalData;
  }, [baseData, liveData]);

  const comparisonData = useMemo(() => 
    historicalData.find(d => d.year === state.compareYear && d.season === state.compareSeason) || historicalData[0],
  [historicalData, state.compareYear, state.compareSeason]);

  // --- Time-Lapse Effect ---
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying) {
      interval = setInterval(() => {
        setState(prev => {
          const currentSeasonIdx = availableSeasons.indexOf(prev.season);

          let nextSeasonIdx = currentSeasonIdx + 1;
          let nextYear = prev.year;

          // Advance season
          if (nextSeasonIdx >= availableSeasons.length) {
            nextSeasonIdx = 0;
            nextYear = prev.year + 1;
          }

          // Loop years if end reached
          const maxYear = Math.max(...availableYears);
          const minYear = Math.min(...availableYears);

          if (nextYear > maxYear) {
            nextYear = minYear;
            nextSeasonIdx = 0;
          }

          return {
            ...prev,
            year: nextYear,
            season: availableSeasons[nextSeasonIdx]
          };
        });
      }, 2000); // 2 seconds per frame
    }
    return () => clearInterval(interval);
  }, [isPlaying, availableYears]);


  // --- Effect: Fetch Real Data from Python Backend ---
  useEffect(() => {
    const fetchRealData = async () => {
        setIsLoadingLive(true);
        try {
            // 1. Fetch Satellite/Physics Data
            const satData = await api.getSatelliteData(
                selectedReservoir.id,
                selectedReservoir.location[0],
                selectedReservoir.location[1],
                state.season,
                selectedReservoir.maxCapacity
            );

            // 2. Check for Anomalies (ML)
            await api.checkAnomaly(satData.data.volume_mcm, baseData.volume);

            setLiveData({
                volume: satData.data.volume_mcm,
                surfaceArea: satData.data.surface_area_sqkm,
                waterLevel: satData.data.water_level_m,
                cloudCover: satData.data.cloud_cover_pct
            });

            // 3. Get ML Forecast for Next Season
            const volumes = historicalData.map(d => d.volume);
            const forecastVal = await api.getForecast(volumes);
            setMlForecast(forecastVal);

            // If the source indicates it's a fallback simulation, mark backend as offline
            if (satData.source.includes('Offline')) {
                setBackendStatus('offline');
            } else {
                setBackendStatus('online');
            }

        } catch (e) {
            console.warn("Backend error, defaulting to offline mode.");
            setBackendStatus('offline');
            setLiveData(null);
            setMlForecast(null);
        } finally {
            setIsLoadingLive(false);
        }
    };

    fetchRealData();
  }, [selectedReservoir, state.season, state.year, historicalData, baseData.volume]);


  const handleStateChange = (newState: Partial<SimulationState>) => {
    setState(prev => ({ ...prev, ...newState }));
    // If user interacts manually, stop playing
    if (newState.year || newState.season || newState.selectedReservoirId) {
        setIsPlaying(false);
    }
    setAiAnalysis(null);
  };

  const handleGenerateAI = async () => {
    setIsGeneratingReport(true);
    try {
      const result = await generateHydrologicalReport(selectedReservoir, currentData, historicalData);
      setAiAnalysis(result);
      return result;
    } catch (e) {
      console.error("AI Generation failed:", e);
      return null;
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleDownloadReport = async () => {
    // If analysis is already there, print immediately
    if (aiAnalysis) {
      window.print();
      return;
    }

    // Otherwise generate it first, then print
    const result = await handleGenerateAI();
    if (result) {
      // Give React time to render the new AIInsights component
      setTimeout(() => {
        window.print();
      }, 800);
    } else {
        alert("Report generation failed. Printing without AI insights.");
        window.print();
    }
  };

  const handleFeedbackSubmit = async (feedback: any) => {
    try {
        await api.sendFeedback(feedback);
        console.log("RLHF Feedback sent.");
    } catch (e) {
        // Quietly fail
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500/30">

      {/* Header */}
      <header className="bg-slate-900/50 backdrop-blur-lg border-b border-slate-800 sticky top-0 z-50 print-hidden">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Waves className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-slate-100 tracking-tight">HydroAI</h1>
              <p className="text-xs text-slate-400">Tamil Nadu Reservoir Monitor</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className={`hidden md:flex items-center gap-4 text-xs font-medium ${backendStatus === 'online' ? 'text-green-500' : 'text-orange-500'}`}>
                <span className="flex items-center gap-1">
                    {backendStatus === 'online' ? <Wifi size={14} /> : <WifiOff size={14}/>} 
                    {backendStatus === 'online' ? "Live Backend" : "Simulated Mode"}
                </span>
             </div>
             <button 
                onClick={handleDownloadReport}
                disabled={isGeneratingReport}
                className="flex items-center gap-2 bg-slate-800 hover:bg-slate-700 disabled:opacity-50 text-slate-200 px-3 py-1.5 rounded-md text-sm transition-colors border border-slate-700 active:scale-95"
             >
                {isGeneratingReport ? (
                    <Loader2 size={14} className="animate-spin" />
                ) : (
                    <Download size={14} />
                )}
                {isGeneratingReport ? "Generating..." : "Download Report"}
             </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-6 space-y-6">

        {/* Print Only Header */}
        <div className="hidden print:block mb-8 border-b border-gray-300 pb-4">
            <div className="flex justify-between items-end">
                <div>
                    <h1 className="text-3xl font-bold text-black mb-1">Hydrological Analysis Report</h1>
                    <p className="text-sm text-gray-600">Generated via HydroAI Geospatial System</p>
                </div>
                <div className="text-right text-sm text-gray-500">
                    <p>Date: {new Date().toLocaleDateString()}</p>
                    <p>Ref ID: {selectedReservoir.id.toUpperCase()}-{state.year}-{state.season}</p>
                </div>
            </div>
        </div>

        {/* Controls Layer (Hidden on Print) */}
        <div className="print-hidden">
            <DashboardControls 
              state={state} 
              onChange={handleStateChange}
              availableSeasons={availableSeasons as any}
              availableYears={availableYears}
              isPlaying={isPlaying}
              onTogglePlay={() => setIsPlaying(!isPlaying)}
            />
        </div>

        {/* Dashboard Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-14rem)] min-h-[600px]">

          {/* Left Column: Map & Key Stats (8 cols) */}
          <div className="lg:col-span-8 flex flex-col gap-6 h-full">

            {/* Map Container */}
            <div className={`flex-1 bg-slate-900 rounded-xl relative group min-h-[300px] map-print-container grid gap-4 transition-all duration-500 ${state.isComparisonMode ? 'grid-cols-2' : 'grid-cols-1'}`}>

                {/* Primary Map */}
                <div className="relative h-full w-full">
                   {isLoadingLive && (
                       <div className="absolute inset-0 z-50 bg-slate-950/60 flex items-center justify-center backdrop-blur-sm">
                           <Loader2 className="animate-spin text-indigo-500 w-8 h-8"/>
                       </div>
                   )}
                   <MapVisualizer 
                      reservoir={selectedReservoir} 
                      data={currentData} 
                      isLive={backendStatus === 'online'}
                      label={state.isComparisonMode ? `${state.season} ${state.year} (Primary)` : undefined}
                   />
                </div>

                {/* Comparison Map */}
                {state.isComparisonMode && (
                  <div className="relative h-full w-full border-l-2 border-slate-700/50">
                    <MapVisualizer 
                      reservoir={selectedReservoir} 
                      data={comparisonData} 
                      isLive={false} // Historical comparison is always "simulated" or "stored"
                      label={`${state.compareSeason} ${state.compareYear} (Comparison)`}
                    />
                    <button 
                       onClick={() => handleStateChange({ isComparisonMode: false })}
                       className="absolute top-2 right-2 z-[500] bg-slate-800 text-slate-300 p-1 rounded-full hover:bg-slate-700 shadow-lg"
                    >
                       <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                    </button>
                  </div>
                )}
            </div>

            {/* Quick Stats Strip */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 print:grid-cols-2">
               <StatCard 
                 label="Water Level" 
                 value={`${currentData.waterLevel} m`} 
                 sub={`FRL: ${selectedReservoir.fullLevel} m`}
                 trend={currentData.waterLevel > (selectedReservoir.fullLevel * 0.8) ? 'up' : 'down'}
               />
               <StatCard 
                 label="Surface Area" 
                 value={`${currentData.surfaceArea} km²`} 
                 sub={backendStatus === 'online' ? "Real-time GEE L2A" : "Simulated NDWI"}
                 icon={<Waves size={14} className="text-blue-400"/>}
               />
               <StatCard 
                 label="Storage Vol" 
                 value={`${currentData.volume} MCM`} 
                 sub={`${Math.round((currentData.volume/selectedReservoir.maxCapacity)*100)}% Capacity`}
                 trend="neutral"
               />
                <StatCard 
                 label="Rainfall" 
                 value={`${currentData.rainfall} mm`} 
                 sub={`${state.season} avg`}
                 icon={<BarChart3 size={14} className="text-blue-400"/>}
               />
            </div>

            {/* Reservoir Details Panel */}
            <div className="bg-slate-900/50 border border-slate-800 p-4 rounded-xl stat-card">
                 <h3 className="text-sm font-semibold text-slate-100 mb-3 flex items-center gap-2">
                    <Info size={16} className="text-indigo-400"/>
                    Reservoir Profile: {selectedReservoir.name}
                 </h3>
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
                    <div className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-lg border border-transparent print:border-gray-200">
                        <Mountain size={18} className="text-emerald-500" />
                        <div>
                            <p className="text-slate-400 text-xs">Catchment Area</p>
                            <p className="font-mono font-medium">{selectedReservoir.catchmentArea} sq km</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-lg border border-transparent print:border-gray-200">
                        <Timer size={18} className="text-orange-500" />
                        <div>
                            <p className="text-slate-400 text-xs">Year Built</p>
                            <p className="font-mono font-medium">{selectedReservoir.yearBuilt}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-lg border border-transparent print:border-gray-200">
                        <Waves size={18} className="text-blue-500" />
                        <div>
                            <p className="text-slate-400 text-xs">Max Capacity</p>
                            <p className="font-mono font-medium">{selectedReservoir.maxCapacity} MCM</p>
                        </div>
                    </div>
                 </div>
            </div>
          </div>

          {/* Right Column: AI & Charts (4 cols) */}
          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-y-auto pr-1">

            <AIInsights 
              analysis={aiAnalysis}
              isLoading={isGeneratingReport}
              onGenerate={handleGenerateAI}
            />

            {aiAnalysis && (
                <ModelFeedback 
                    analysis={aiAnalysis} 
                    data={currentData as SeasonalData} 
                    onFeedbackSubmit={handleFeedbackSubmit} 
                />
            )}

            <VolumeChart 
              data={historicalData} 
              forecast={mlForecast} 
              maxCapacity={selectedReservoir.maxCapacity}
            />

            <div className="bg-slate-900/50 border border-slate-800 p-4 rounded-xl print-hidden">
               <div className="flex items-center gap-2 mb-2 text-slate-100 font-medium">
                  <Info size={16} />
                  <span className="text-sm">Technical Methodology</span>
               </div>
               <p className="text-xs text-slate-400 leading-relaxed">
                 Data fetched from <strong>Backend GEE Pipeline</strong>. Water spread extracted via U-Net CNN (Simulated). Anomaly Detection via Isolation Forest.
               </p>
            </div>
          </div>
        </div>

        {/* Floating Chatbot */}
        <HydroChat reservoir={selectedReservoir} currentData={currentData} />
      </main>
    </div>
  );
};

const StatCard: React.FC<{label: string, value: string, sub: string, trend?: 'up'|'down'|'neutral', icon?: React.ReactNode}> = ({label, value, sub, trend, icon}) => (
  <div className="bg-slate-900/80 border border-slate-800 p-4 rounded-xl hover:border-slate-700 transition-colors stat-card">
    <div className="flex justify-between items-start mb-2">
      <span className="text-slate-500 text-xs font-semibold uppercase tracking-wider">{label}</span>
      {icon}
    </div>
    <div className="text-2xl font-bold text-slate-100 mb-1">{value}</div>
    <div className="flex items-center gap-2">
       {trend && (
         <span className={`text-xs px-1.5 py-0.5 rounded ${
           trend === 'up' ? 'bg-green-500/20 text-green-400' : 
           trend === 'down' ? 'bg-red-500/20 text-red-400' : 'bg-slate-700 text-slate-400'
         }`}>
           {trend === 'up' ? '↑' : trend === 'down' ? '↓' : '-'}
         </span>
       )}
       <span className="text-xs text-slate-400 truncate">{sub}</span>
    </div>
  </div>
);

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { MessageCircle, X, Send, Bot, User, Loader2, Sparkles, Minimize2, Maximize2, Globe, ExternalLink } from 'lucide-react';
import { Reservoir, SeasonalData } from '../types';
import { RESERVOIRS } from '../services/mockData';

interface HydroChatProps {
  reservoir: Reservoir;
  currentData: SeasonalData;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  sources?: { title: string; uri: string }[];
}

const HydroChat: React.FC<HydroChatProps> = ({ reservoir, currentData }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: `Hello! I'm tracking ${reservoir.name} and 5 other key reservoirs. I can use Google Search to find the latest news, rainfall alerts, and outflow data. How can I help?` }
  ]);
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen, isThinking]);

  // Reset chat when reservoir changes to avoid stale context
  useEffect(() => {
    setMessages(prev => [
        ...prev,
        { role: 'model', text: `Switched context to ${reservoir.name}. I have access to live web data if you need the absolute latest updates.` }
    ]);
  }, [reservoir.id]);

  const handleSend = async () => {
    if (!input.trim() || isThinking) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsThinking(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const reservoirList = RESERVOIRS.map(r => r.name).join(', ');

      const systemContext = `
        You are HydroChat, an AI assistant for the Tamil Nadu Water Resources Department dashboard.

        KEY CAPABILITY:
        You have access to Google Search. You MUST use it to answer questions about "current", "latest", "today's", or "live" statuses.

        MONITORED RESERVOIRS:
        ${reservoirList}

        CURRENT DASHBOARD CONTEXT (Simulated/Historical Data):
        Selected Reservoir: ${reservoir.name}
        Season displayed on map: ${currentData.season} ${currentData.year}
        Volume displayed: ${currentData.volume} MCM

        INSTRUCTIONS:
        1. If the user asks about the *current dashboard view*, use the Dashboard Context provided above.
        2. If the user asks for *real-time/live* news, outflows, or weather (e.g., "What is the outflow today?", "Any flood alerts?"), IGNORE the dashboard context and USE GOOGLE SEARCH to find the actual latest information from news sources or government bulletins (like tnwrd.gov.in).
        3. Keep answers concise (under 100 words).
        4. Always cite your sources if you use Google Search.
      `;

      // Construct history for context
      const chatHistory = messages.map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
      }));

      // Initialize chat with system instruction and Search Tool
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
            systemInstruction: systemContext,
            tools: [{ googleSearch: {} }] // Enable Web Search
        },
        history: chatHistory
      });

      const result = await chat.sendMessageStream({ message: userMsg });

      let fullResponse = "";
      let collectedSources: { title: string; uri: string }[] = [];

      setMessages(prev => [...prev, { role: 'model', text: "" }]);

      for await (const chunk of result) {
        const text = chunk.text;
        if (text) {
          fullResponse += text;
        }

        // Extract grounding metadata (sources)
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
            groundingChunks.forEach((c: any) => {
                if (c.web?.uri && c.web?.title) {
                    // Avoid duplicates
                    if (!collectedSources.find(s => s.uri === c.web.uri)) {
                        collectedSources.push({ title: c.web.title, uri: c.web.uri });
                    }
                }
            });
        }

        setMessages(prev => {
            const newMsgs = [...prev];
            const lastMsg = newMsgs[newMsgs.length - 1];
            lastMsg.text = fullResponse;
            // Update sources if found
            if (collectedSources.length > 0) {
                lastMsg.sources = collectedSources;
            }
            return newMsgs;
        });
      }

    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, { role: 'model', text: "I encountered an error connecting to the AI service. Please check your network or API key configuration." }]);
    } finally {
      setIsThinking(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-lg shadow-indigo-900/50 transition-all hover:scale-110 print-hidden"
      >
        <MessageCircle size={28} />
        <span className="absolute -top-1 -right-1 flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-sky-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-sky-500"></span>
        </span>
      </button>
    );
  }

  return (
    <div className={`fixed z-50 bg-slate-900 border border-slate-700 shadow-2xl transition-all duration-300 flex flex-col print-hidden ${isMinimized ? 'bottom-6 right-6 w-72 h-14 rounded-full overflow-hidden' : 'bottom-6 right-6 w-96 h-[500px] rounded-xl'}`}>

      {/* Header */}
      <div className={`flex items-center justify-between p-4 bg-slate-800 border-b border-slate-700 cursor-pointer ${isMinimized ? 'h-full' : ''}`} onClick={() => isMinimized && setIsMinimized(false)}>
        <div className="flex items-center gap-2">
          <div className="p-1.5 bg-indigo-600 rounded-lg">
             <Sparkles size={16} className="text-white" />
          </div>
          <h3 className="font-bold text-slate-100 text-sm">HydroChat AI <span className="text-[10px] bg-sky-900/50 text-sky-300 px-1 rounded ml-1 border border-sky-800">Live</span></h3>
        </div>
        <div className="flex items-center gap-1">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsMinimized(!isMinimized); }}
            className="p-1 hover:bg-slate-700 rounded text-slate-400"
          >
             {isMinimized ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); setIsOpen(false); setIsMinimized(false); }}
            className="p-1 hover:bg-red-900/50 rounded text-slate-400 hover:text-red-400"
          >
             <X size={16}/>
          </button>
        </div>
      </div>

      {!isMinimized && (
        <>
          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/95 scrollbar-thin">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex flex-col gap-1 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    {msg.role === 'model' && (
                    <div className="w-6 h-6 rounded-full bg-indigo-900/50 border border-indigo-700 flex items-center justify-center flex-shrink-0 mt-1">
                        <Bot size={14} className="text-indigo-400"/>
                    </div>
                    )}
                    <div className={`max-w-[90%] rounded-lg p-3 text-sm leading-relaxed ${
                    msg.role === 'user' 
                        ? 'bg-indigo-600 text-white rounded-br-none' 
                        : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-bl-none'
                    }`}>
                    {msg.text ? (
                        msg.text.split('\n').map((line, i) => (
                            <p key={i} className="mb-1 last:mb-0">{line}</p>
                        ))
                    ) : (
                        <span className="animate-pulse">...</span>
                    )}
                    </div>
                    {msg.role === 'user' && (
                    <div className="w-6 h-6 rounded-full bg-slate-700 border border-slate-600 flex items-center justify-center flex-shrink-0 mt-1">
                        <User size={14} className="text-slate-300"/>
                    </div>
                    )}
                  </div>

                  {/* Sources / Grounding Chips */}
                  {msg.sources && msg.sources.length > 0 && (
                      <div className="flex flex-wrap gap-2 ml-9 max-w-[90%] mt-1">
                          {msg.sources.map((source, sIdx) => (
                              <a 
                                key={sIdx} 
                                href={source.uri} 
                                target="_blank" 
                                rel="noopener noreferrer"
                                className="flex items-center gap-1 text-[10px] bg-slate-950 border border-slate-700 text-sky-400 px-2 py-1 rounded-full hover:bg-slate-800 transition-colors"
                              >
                                  <Globe size={10} />
                                  <span className="truncate max-w-[150px]">{source.title}</span>
                                  <ExternalLink size={10} />
                              </a>
                          ))}
                      </div>
                  )}
              </div>
            ))}

            {isThinking && (
              <div className="flex gap-3 justify-start">
                  <div className="w-6 h-6 rounded-full bg-indigo-900/50 border border-indigo-700 flex items-center justify-center flex-shrink-0 mt-1">
                    <Bot size={14} className="text-indigo-400"/>
                  </div>
                  <div className="bg-slate-800 border border-slate-700 rounded-lg p-3 rounded-bl-none flex items-center gap-2">
                     <Loader2 size={16} className="animate-spin text-indigo-400"/>
                     <span className="text-xs text-slate-400">Searching live data...</span>
                  </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
