        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-auto lg:h-[calc(100vh-14rem)] lg:min-h-[600px]">

          {/* Left Column: Map & Key Stats (8 cols) */}
          <div className="lg:col-span-8 flex flex-col gap-6 h-auto lg:h-full">

            {/* Map Container */}
